import socket
import struct
import time
import random

class CoapCode:
    GET = 1
    POST = 2
    PUT = 3
    DELETE = 4
    CONTENT = 69
    CHANGED = 68
    BAD_REQUEST = 128
    NOT_FOUND = 132
    METHOD_NOT_ALLOWED = 133

class CoapType:
    CON = 0
    NON = 1
    ACK = 2
    RST = 3

class CoapServer:
    def __init__(self, host='0.0.0.0', port=5683):
        self.host = host
        self.port = port
        self.resources = {}
        self.sock = None
        
    def add_resource(self, path, get_handler=None, put_handler=None):
        self.resources[path] = {
            'get': get_handler,
            'put': put_handler
        }
    
    def parse_coap_message(self, data):
        if len(data) < 4:
            return None
        
        version = (data[0] >> 6) & 0x03
        msg_type = (data[0] >> 4) & 0x03
        token_length = data[0] & 0x0F
        code = data[1]
        msg_id = struct.unpack('!H', data[2:4])[0]
        
        offset = 4
        token = data[offset:offset + token_length] if token_length > 0 else b''
        offset += token_length
        
        options = []
        option_delta = 0
        
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                break
            
            delta = (data[offset] >> 4) & 0x0F
            length = data[offset] & 0x0F
            offset += 1
            
            if delta == 13:
                delta = data[offset] + 13
                offset += 1
            elif delta == 14:
                delta = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
            
            if length == 13:
                length = data[offset] + 13
                offset += 1
            elif length == 14:
                length = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
            
            option_delta += delta
            option_value = data[offset:offset + length]
            offset += length
            
            options.append((option_delta, option_value))
        
        payload = data[offset:] if offset < len(data) else b''
        
        return {
            'version': version,
            'type': msg_type,
            'token_length': token_length,
            'code': code,
            'msg_id': msg_id,
            'token': token,
            'options': options,
            'payload': payload
        }
    
    def build_coap_response(self, msg_type, code, msg_id, token, options=None, payload=b''):
        header = bytearray(4)
        header[0] = (1 << 6) | (msg_type << 4) | len(token)
        header[1] = code
        struct.pack_into('!H', header, 2, msg_id)
        
        response = header + token
        
        if options:
            prev_delta = 0
            for opt_num, opt_val in sorted(options):
                delta = opt_num - prev_delta
                length = len(opt_val)
                
                opt_header = (delta << 4) | length
                response += bytes([opt_header]) + opt_val
                prev_delta = opt_num
        
        if payload:
            response += b'\xFF' + payload
        
        return response
    
    def get_uri_path(self, options):
        path_parts = []
        for opt_num, opt_val in options:
            if opt_num == 11:
                path_parts.append(opt_val.decode('utf-8'))
        return '/' + '/'.join(path_parts) if path_parts else '/'
    
    def handle_request(self, data, addr):
        msg = self.parse_coap_message(data)
        if not msg:
            return None
        
        uri_path = self.get_uri_path(msg['options'])
        
        if uri_path not in self.resources:
            response = self.build_coap_response(
                CoapType.ACK,
                CoapCode.NOT_FOUND,
                msg['msg_id'],
                msg['token']
            )
            return response
        
        resource = self.resources[uri_path]
        
        if msg['code'] == CoapCode.GET:
            if resource['get']:
                payload = resource['get']()
                response = self.build_coap_response(
                    CoapType.ACK,
                    CoapCode.CONTENT,
                    msg['msg_id'],
                    msg['token'],
                    options=[(12, b'0')],
                    payload=payload
                )
                return response
            else:
                response = self.build_coap_response(
                    CoapType.ACK,
                    CoapCode.METHOD_NOT_ALLOWED,
                    msg['msg_id'],
                    msg['token']
                )
                return response
        
        elif msg['code'] == CoapCode.PUT:
            if resource['put']:
                resource['put'](msg['payload'])
                response = self.build_coap_response(
                    CoapType.ACK,
                    CoapCode.CHANGED,
                    msg['msg_id'],
                    msg['token']
                )
                return response
            else:
                response = self.build_coap_response(
                    CoapType.ACK,
                    CoapCode.METHOD_NOT_ALLOWED,
                    msg['msg_id'],
                    msg['token']
                )
                return response
        
        else:
            response = self.build_coap_response(
                CoapType.ACK,
                CoapCode.BAD_REQUEST,
                msg['msg_id'],
                msg['token']
            )
            return response
    
    def start(self):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)
        
        print(f"CoAP server started on {self.host}:{self.port}")
        
        while True:
            try:
                data, addr = self.sock.recvfrom(1024)
                response = self.handle_request(data, addr)
                if response:
                    self.sock.sendto(response, addr)
            except OSError:
                pass
            except Exception as e:
                print(f"Error: {e}")

temperature = 22.5
light_state = False

def get_temperature():
    global temperature
    temp_str = f"{temperature:.1f}"
    return temp_str.encode('utf-8')

def get_light():
    global light_state
    state = "ON" if light_state else "OFF"
    return state.encode('utf-8')

def put_light(payload):
    global light_state
    value = payload.decode('utf-8').strip().upper()
    if value == "ON" or value == "1":
        light_state = True
        print("Light turned ON")
    elif value == "OFF" or value == "0":
        light_state = False
        print("Light turned OFF")

server = CoapServer()

server.add_resource('/sensors/temp', get_handler=get_temperature)
server.add_resource('/actuators/light', get_handler=get_light, put_handler=put_light)

server.start()